ee:message.ee:set-payload:
%dw 2.0
output application/json


fun toLKR(usdAmount: Number) = usdAmount * 300


var enrichedPayload = payload map (item) -> item ++ {
    lineTotalLKR: toLKR(item.priceUSD * item.quantity)
}
---
{
    "metadata": {
        "timestamp": now() as String {format: "yyyy-MM-dd'T'HH:mm:ss'Z'"},
        "totalItems": sizeOf(payload)
    },


    "localSupplierOrder": enrichedPayload filter ($.partId startsWith "LOC") map (item) -> {
        "id": item.partId,
        "description": item.name,
        "qty": item.quantity,
        "costLKR": item.lineTotalLKR
    },


    "importedSupplierOrder": enrichedPayload filter ($.partId startsWith "IMP") map (item) -> {
        "id": item.partId,
        "description": item.name,
        "qty": item.quantity,
        "costLKR": item.lineTotalLKR
    },

    "totalOrderValueLKR": enrichedPayload.lineTotalLKR reduce ($ + $$) default 0
}
